import{_ as e,o as l,c as t,a7 as i}from"./chunks/framework.C5fSpjcB.js";const m=JSON.parse('{"title":"戦闘システム","description":"","frontmatter":{},"headers":[],"relativePath":"ja/modes/combat.md","filePath":"ja/modes/combat.md","lastUpdated":1775394001000}'),r={name:"ja/modes/combat.md"};function o(s,a,d,h,n,c){return l(),t("div",null,[...a[0]||(a[0]=[i('<h1 id="戦闘システム" tabindex="-1">戦闘システム <a class="header-anchor" href="#戦闘システム" aria-label="Permalink to &quot;戦闘システム&quot;">​</a></h1><p>忘却前夜の戦闘はターン制カードバトルです。手札のカードを算力（Arithmetica）を消費してプレイし、敵を撃破します。</p><h2 id="戦闘の流れ" tabindex="-1">戦闘の流れ <a class="header-anchor" href="#戦闘の流れ" aria-label="Permalink to &quot;戦闘の流れ&quot;">​</a></h2><h3 id="_1-ドローフェイズ" tabindex="-1">1. ドローフェイズ <a class="header-anchor" href="#_1-ドローフェイズ" aria-label="Permalink to &quot;1. ドローフェイズ&quot;">​</a></h3><ul><li>デッキからカードをドローして手札に加える</li><li>通常は毎ターン5枚ドロー</li><li>超維界域のシナジーで追加ドローが可能</li></ul><h3 id="_2-算力回復フェイズ" tabindex="-1">2. 算力回復フェイズ <a class="header-anchor" href="#_2-算力回復フェイズ" aria-label="Permalink to &quot;2. 算力回復フェイズ&quot;">​</a></h3><ul><li><strong>算力が5回復</strong>する（基本値）</li><li>超維界域シナジーや鍵令効果で追加回復あり</li><li>前ターンの余剰算力は持ち越し不可</li></ul><h3 id="_3-メインフェイズ" tabindex="-1">3. メインフェイズ <a class="header-anchor" href="#_3-メインフェイズ" aria-label="Permalink to &quot;3. メインフェイズ&quot;">​</a></h3><ul><li>手札のカードを任意の順番でプレイ</li><li>各カードのコスト分の算力を消費</li><li>カード効果が即座に発動</li></ul><h3 id="_4-エンドフェイズ" tabindex="-1">4. エンドフェイズ <a class="header-anchor" href="#_4-エンドフェイズ" aria-label="Permalink to &quot;4. エンドフェイズ&quot;">​</a></h3><ul><li>未使用カードは手札に残留（手札上限あり）</li><li>ターン終了時効果が発動</li><li>次のターンへ</li></ul><h2 id="狂気-madness-システム" tabindex="-1">狂気（Madness）システム <a class="header-anchor" href="#狂気-madness-システム" aria-label="Permalink to &quot;狂気（Madness）システム&quot;">​</a></h2><ul><li>カード使用・被ダメージ等で<strong>狂気ゲージ</strong>が蓄積</li><li><strong>狂気ゲージが100に到達</strong>すると魂覚醒カード（バースト）が使用可能</li><li>バースト使用後、狂気ゲージはリセットされる</li><li>混沌界域の覚醒体は蓄積が特に速い</li></ul><h2 id="銀鍵-silver-key-システム" tabindex="-1">銀鍵（Silver Key）システム <a class="header-anchor" href="#銀鍵-silver-key-システム" aria-label="Permalink to &quot;銀鍵（Silver Key）システム&quot;">​</a></h2><ul><li>特定の行動で<strong>銀鍵ゲージ</strong>が蓄積（最大1000）</li><li>銀鍵ゲージに応じて鍵令の効果が発動</li><li>中〜終盤で解放される上級システム</li></ul><h2 id="属性相性" tabindex="-1">属性相性 <a class="header-anchor" href="#属性相性" aria-label="Permalink to &quot;属性相性&quot;">​</a></h2><p><em>準備中...</em></p><h2 id="状態異常" tabindex="-1">状態異常 <a class="header-anchor" href="#状態異常" aria-label="Permalink to &quot;状態異常&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">状態異常</th><th style="text-align:left;">効果</th></tr></thead><tbody><tr><td style="text-align:left;"><em>準備中...</em></td><td style="text-align:left;">—</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>算力は毎ターン5しかないため、コスト管理が勝敗を分けます。低コストカードで手数を増やすか、高コストカードで一撃を狙うか、戦略を立てましょう。</p></div><h2 id="関連ページ" tabindex="-1">関連ページ <a class="header-anchor" href="#関連ページ" aria-label="Permalink to &quot;関連ページ&quot;">​</a></h2><ul><li><a href="./../cards/">カードシステム概要</a></li><li><a href="./../cards/deckbuilding.html">デッキ構築ガイド</a></li><li><a href="./../awakeners/team-building.html">編成ガイド</a></li><li><a href="./../key-orders/">鍵令概要</a></li></ul>',22)])])}const b=e(r,[["render",o]]);export{m as __pageData,b as default};
